module shift_reg16(din, clk, rst, dout);
    input din;
    input clk;
    input rst;
    output reg [15:0] dout;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            dout <= 16'b0;
        else
            dout <= {dout[14:0], din};
    end
endmodule
